// PANTALLA 1: LOGIN
// ═══════════════════════════════════════════════════════════════
function Login({ onLogin }) {
  const [email, setEmail] = useState("rogelio.hernandez@bigticket.mx");
  const [pass, setPass] = useState("demo123");
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [recovery, setRecovery] = useState(false);

  const handleLogin = () => {
    if (!email || !pass) return;
    setLoading(true);
    setTimeout(() => { setLoading(false); onLogin(); }, 900);
  };

  if (recovery) {
    return (
      <div style={{ padding: "40px 28px", minHeight: "100%", display: "flex", flexDirection: "column" }}>
        <button onClick={() => setRecovery(false)} className="bt-back" style={{ marginBottom: 24 }}>
          <Icon name="back" size={20} />
        </button>
        <h1 style={{ fontSize: 28, fontWeight: 800, color: C.azul, marginBottom: 6, letterSpacing: -.8 }}>
          Recuperar contraseña
        </h1>
        <p style={{ color: C.gris2, fontSize: 14, marginBottom: 32, lineHeight: 1.5 }}>
          Ingresa tu correo y te enviaremos un enlace para restablecer tu contraseña.
        </p>
        <label style={{ fontSize: 13, color: C.gris1, fontWeight: 600, marginBottom: 8 }}>Correo</label>
        <input type="email" className="bt-input" placeholder="tu@correo.com" style={{ marginBottom: 20 }} />
        <button className="bt-btn" onClick={() => { alert("Correo enviado (simulación)"); setRecovery(false); }}>
          Enviar enlace
        </button>
      </div>
    );
  }

  return (
    <div style={{
      minHeight: "100%", display: "flex", flexDirection: "column",
      background: C.azulLogo, padding: "40px 24px 28px",
    }}>
      {/* Logo Bigticket — fondo del mismo azul, sin bordes visibles */}
      <div style={{ textAlign: "center", padding: "30px 0 38px" }}>
        <img
          src={BIGTICKET_LOGO_URL}
          alt="Bigticket"
          style={{ width: 210, height: "auto", display: "block", margin: "0 auto" }}
        />
      </div>

      {/* Card blanca flotando */}
      <div style={{
        background: "#fff", borderRadius: 20, padding: 24,
        boxShadow: "0 20px 50px rgba(0,0,0,.25)",
        border: `1px solid ${C.borde}`,
      }}>
        <h2 style={{ fontSize: 18, fontWeight: 700, color: C.azul, marginBottom: 4 }}>Bienvenido 👋</h2>
        <p style={{ fontSize: 13, color: C.gris2, marginBottom: 22 }}>Ingresa con tu cuenta para continuar</p>

        <label style={{ fontSize: 12, color: C.gris1, fontWeight: 600, letterSpacing: .3, textTransform: "uppercase", marginBottom: 8, display: "block" }}>
          Correo electrónico
        </label>
        <div style={{ position: "relative", marginBottom: 16 }}>
          <input type="email" className="bt-input" style={{ paddingLeft: 44 }} value={email} onChange={e => setEmail(e.target.value)} />
          <div style={{ position: "absolute", left: 14, top: 15 }}>
            <Icon name="mail" size={18} color={C.gris3} />
          </div>
        </div>

        <label style={{ fontSize: 12, color: C.gris1, fontWeight: 600, letterSpacing: .3, textTransform: "uppercase", marginBottom: 8, display: "block" }}>
          Contraseña
        </label>
        <div style={{ position: "relative", marginBottom: 10 }}>
          <input type={showPass ? "text" : "password"} className="bt-input" style={{ paddingLeft: 44, paddingRight: 44 }} value={pass} onChange={e => setPass(e.target.value)} />
          <div style={{ position: "absolute", left: 14, top: 15 }}>
            <Icon name="lock" size={18} color={C.gris3} />
          </div>
          <button onClick={() => setShowPass(!showPass)} style={{ position: "absolute", right: 10, top: 12, background: "transparent", border: "none", cursor: "pointer", padding: 4, color: C.gris2 }}>
            <Icon name={showPass ? "eyeOff" : "eye"} size={18} />
          </button>
        </div>

        <button onClick={() => setRecovery(true)} style={{ background: "none", border: "none", color: C.azul, fontSize: 13, fontWeight: 600, cursor: "pointer", marginBottom: 24, padding: 0 }}>
          ¿Olvidaste tu contraseña?
        </button>

        <button className="bt-btn" onClick={handleLogin} disabled={loading}>
          {loading ? "Iniciando sesión..." : "Iniciar sesión"}
        </button>
      </div>

      {/* Footer sobre fondo azul */}
      <div style={{ textAlign: "center", marginTop: "auto", paddingTop: 24 }}>
        <p style={{ fontSize: 12, color: "rgba(255,255,255,.65)" }}>
          ¿Problemas para ingresar?{" "}
          <span style={{ color: C.naranja, fontWeight: 600 }}>Contacta a Bigticket</span>
        </p>
      </div>
    </div>
  );
}
// ═══════════════════════════════════════════════════════════════
// PANTALLA 2: SPLASH DE BIENVENIDA (primera entrada)
// ═══════════════════════════════════════════════════════════════
function Splash({ onContinue }) {
  const [step, setStep] = useState(0);
  const mensajes = [
    { title: `¡Hola, ${DRIVER.nombre}! 👋`, body: `Soy Biggi, tu asistente en Bigticket. Estoy acá para acompañarte en el día a día.` },
    { title: "Todo en un solo lugar", body: "Acá vas a ver tus pagos, tu desempeño, tus rutas y tus documentos. Todo actualizado al instante." },
    { title: "Preguntame lo que sea", body: "¿Dudas sobre el pago? ¿Cómo subir un documento? Abrime cuando necesites ayuda." },
  ];
  const cur = mensajes[step];

  return (
    <div style={{
      minHeight: "100%", display: "flex", flexDirection: "column", padding: "48px 28px 30px",
      background: `linear-gradient(160deg, #fff 0%, ${C.bg3} 70%)`,
    }}>
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center" }}>
        <div style={{
          width: 170, height: 170, borderRadius: "50%", border: `5px solid ${C.naranja}`,
          overflow: "hidden", marginBottom: 34, boxShadow: "0 15px 40px rgba(244,123,32,.25)",
        }}>
          <img src={BIGGI_URL} alt="Biggi" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
        </div>
        <h1 style={{ fontSize: 26, fontWeight: 800, color: C.azul, marginBottom: 12, letterSpacing: -.6 }}>
          {cur.title}
        </h1>
        <p style={{ fontSize: 15, color: C.gris1, lineHeight: 1.6, maxWidth: 300 }}>
          {cur.body}
        </p>
      </div>

      {/* Dots */}
      <div style={{ display: "flex", justifyContent: "center", gap: 8, marginBottom: 24 }}>
        {mensajes.map((_, i) => (
          <div key={i} style={{
            width: step === i ? 24 : 8, height: 8, borderRadius: 4,
            background: step === i ? C.naranja : C.borde, transition: ".3s",
          }} />
        ))}
      </div>

      <button className="bt-btn" onClick={() => {
        if (step < mensajes.length - 1) setStep(step + 1); else onContinue();
      }}>
        {step < mensajes.length - 1 ? "Siguiente" : "Entrar a mi portal"}
      </button>
      {step < mensajes.length - 1 && (
        <button onClick={onContinue} style={{ background: "none", border: "none", color: C.gris2, fontSize: 13, marginTop: 14, cursor: "pointer" }}>
          Omitir
        </button>
      )}
    </div>
  );
}

