function Stat({ label, valor, color }) {
  return (
    <div>
      <p style={{ fontSize: 11, color: C.gris2, marginBottom: 2, fontWeight: 500 }}>{label}</p>
      <p style={{ fontSize: 16, fontWeight: 700, color: color || C.azul, letterSpacing: -.3 }}>{valor}</p>
    </div>
  );
}

function MiniCard({ label, valor, sub, icon, color }) {
  return (
    <div style={{ background: "#fff", borderRadius: 14, padding: 14, border: `1px solid ${C.borde}` }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
        <p style={{ fontSize: 11, color: C.gris2, fontWeight: 600, letterSpacing: .3, textTransform: "uppercase" }}>{label}</p>
        <div style={{ width: 26, height: 26, borderRadius: 8, background: color + "15", display: "flex", alignItems: "center", justifyContent: "center", color }}>
          <Icon name={icon} size={14} />
        </div>
      </div>
      <p style={{ fontSize: 20, fontWeight: 800, color: C.azul, letterSpacing: -.4, marginBottom: 2 }}>{valor}</p>
      <p style={{ fontSize: 11, color: C.gris2 }}>{sub}</p>
    </div>
  );
}

const MESES_ABREV = ["ENE", "FEB", "MAR", "ABR", "MAY", "JUN", "JUL", "AGO", "SEP", "OCT", "NOV", "DIC"];
const DIAS_ABREV = ["DOM", "LUN", "MAR", "MIÉ", "JUE", "VIE", "SÁB"];

function parsearFecha(fechaStr) {
  // Parseo directo del string YYYY-MM-DD para evitar problemas de timezone/locale
  const [y, m, d] = fechaStr.split("-").map(Number);
  return { y, m, d, dia: String(d).padStart(2, "0"), mesAbrev: MESES_ABREV[m - 1] };
}

function RutaRow({ ruta, onClick }) {
  const f = parsearFecha(ruta.fecha);
  const nsColor = ruta.ns >= 99.5 ? C.verde : ruta.ns >= 98 ? C.gris1 : ruta.ns >= 95 ? C.naranja : C.rojo;
  return (
    <div
      onClick={onClick}
      style={{
        background: "#fff", border: `1px solid ${C.borde}`, borderRadius: 14,
        padding: 14, display: "flex", alignItems: "center", gap: 12,
        cursor: onClick ? "pointer" : "default", transition: ".15s",
      }}>
      <div style={{ width: 42, height: 42, background: C.badgeAzul, borderRadius: 10, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", color: C.azul, fontWeight: 700 }}>
        <span style={{ fontSize: 10, opacity: .7 }}>{f.mesAbrev}</span>
        <span style={{ fontSize: 15, lineHeight: 1 }}>{f.dia}</span>
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 2 }}>
          <span style={{ fontSize: 13, fontWeight: 600, color: C.azul }}>Ruta #{ruta.id}</span>
        </div>
        <p style={{ fontSize: 11, color: C.gris2 }}>
          {ruta.entregadas}/{ruta.paradas} entregas · {ruta.km} km · <span style={{ color: nsColor, fontWeight: 600 }}>{ruta.ns}% NS</span>
        </p>
      </div>
      <div style={{ textAlign: "right" }}>
        <p style={{ fontSize: 15, fontWeight: 700, color: C.azul }}>${ruta.monto.toLocaleString("es-MX")}</p>
        <p style={{ fontSize: 10, color: ruta.ajuste > 0 ? C.verde : ruta.ajuste < 0 ? C.rojo : C.gris2, fontWeight: 600 }}>
          {ruta.ajuste > 0 ? "+" : ""}{ruta.ajuste}%
        </p>
      </div>
      {onClick && (
        <div style={{ color: C.gris3 }}>
          <Icon name="back" size={14} strokeWidth={2.5} />
        </div>
      )}
    </div>
  );
}
// ═══════════════════════════════════════════════════════════════
// PANTALLA 4: MIS PAGOS
// ═══════════════════════════════════════════════════════════════
function Pagos({ onBack, onAbrirJornada }) {
  const [filtro, setFiltro] = useState("semana");
  const totalSemana = RUTAS.slice(0, 5).reduce((s, r) => s + r.monto, 0);
  const totalMes = totalSemana * 4 + 1850; // mock

  // Pago histórico
  const pagos = [
    { periodo: "Semana 17 (22–28 abr)", dias: 5, monto: totalSemana, estado: "en_curso" },
    { periodo: "Semana 16 (15–21 abr)", dias: 6, monto: 12840, estado: "pagado", fecha_pago: "2026-04-21" },
    { periodo: "Semana 15 (8–14 abr)", dias: 5, monto: 10560, estado: "pagado", fecha_pago: "2026-04-14" },
    { periodo: "Semana 14 (1–7 abr)", dias: 6, monto: 11920, estado: "pagado", fecha_pago: "2026-04-07" },
  ];

  const maxBar = Math.max(...RUTAS.map(r => r.monto));

  return (
    <div>
      <div className="bt-header">
        <button className="bt-back" onClick={onBack}><Icon name="back" size={20} /></button>
        <div className="bt-header-title">Mis Pagos</div>
      </div>

      <div style={{ padding: 20 }}>
        {/* Card total */}
        <div style={{
          background: `linear-gradient(135deg, ${C.azul} 0%, #2a5490 100%)`,
          borderRadius: 20, padding: 22, color: "#fff", marginBottom: 20,
          boxShadow: "0 14px 30px rgba(26,58,107,.25)",
        }}>
          <p style={{ fontSize: 12, opacity: .85, fontWeight: 600, letterSpacing: .5, textTransform: "uppercase", marginBottom: 6 }}>
            Esta semana
          </p>
          <div style={{ display: "flex", alignItems: "baseline", gap: 6, marginBottom: 14 }}>
            <span style={{ fontSize: 40, fontWeight: 800, letterSpacing: -1.5 }}>
              ${totalSemana.toLocaleString("es-MX")}
            </span>
            <span style={{ fontSize: 14, opacity: .9 }}>MXN</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", paddingTop: 14, borderTop: "1px solid rgba(255,255,255,.2)" }}>
            <div>
              <p style={{ fontSize: 11, opacity: .8, marginBottom: 1 }}>Próximo pago</p>
              <p style={{ fontSize: 13, fontWeight: 600 }}>Lunes 28 de abril</p>
            </div>
            <div style={{ textAlign: "right" }}>
              <p style={{ fontSize: 11, opacity: .8, marginBottom: 1 }}>Días trabajados</p>
              <p style={{ fontSize: 13, fontWeight: 600 }}>5 de 6</p>
            </div>
          </div>
        </div>

        {/* Gráfico de barras semanal */}
        <div style={{ background: "#fff", borderRadius: 16, padding: 18, border: `1px solid ${C.borde}`, marginBottom: 20 }}>
          <h3 style={{ fontSize: 14, fontWeight: 700, color: C.azul, marginBottom: 16 }}>Ganancia por día</h3>
          <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", height: 120, gap: 6, marginBottom: 10 }}>
            {[...RUTAS].reverse().map((r, i) => {
              const h = (r.monto / maxBar) * 100;
              const color = r.ajuste > 0 ? C.verde : r.ajuste < 0 ? C.rojo : C.azul;
              return (
                <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 5 }}>
                  <span style={{ fontSize: 9, color: C.gris2, fontWeight: 600 }}>${(r.monto/1000).toFixed(1)}k</span>
                  <div style={{
                    width: "100%", height: `${h}%`, minHeight: 10,
                    background: color, borderRadius: "6px 6px 2px 2px", transition: ".3s",
                  }} />
                  <span style={{ fontSize: 10, color: C.gris2 }}>
                    {(() => {
                      const [y, m, d] = r.fecha.split("-").map(Number);
                      const diaSem = new Date(Date.UTC(y, m - 1, d)).getUTCDay();
                      return DIAS_ABREV[diaSem].slice(0, 3);
                    })()}
                  </span>
                </div>
              );
            })}
          </div>
          <div style={{ display: "flex", justifyContent: "center", gap: 14, paddingTop: 8, borderTop: `1px solid ${C.borde}` }}>
            <Leg color={C.verde} label="Con premio" />
            <Leg color={C.azul} label="Neutro" />
            <Leg color={C.rojo} label="Con multa" />
          </div>
        </div>

        {/* Histórico */}
        <h3 style={{ fontSize: 14, fontWeight: 700, color: C.azul, marginBottom: 12, letterSpacing: .3, textTransform: "uppercase" }}>
          Histórico
        </h3>
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {pagos.map((p, i) => <PagoRow key={i} pago={p} />)}
        </div>

        {/* Detalle día a día */}
        <h3 style={{ fontSize: 14, fontWeight: 700, color: C.azul, marginBottom: 12, marginTop: 24, letterSpacing: .3, textTransform: "uppercase" }}>
          Detalle por día
        </h3>
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {RUTAS.map((r, i) => (
            <RutaRow key={i} ruta={r} onClick={() => onAbrirJornada && onAbrirJornada(r)} />
          ))}
        </div>
      </div>
    </div>
  );
}

function Leg({ color, label }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
      <div style={{ width: 10, height: 10, borderRadius: 3, background: color }} />
      <span style={{ fontSize: 10, color: C.gris2, fontWeight: 600 }}>{label}</span>
    </div>
  );
}

function PagoRow({ pago }) {
  const colors = {
    pagado: { bg: C.verdeClaro, text: C.verde, label: "Pagado" },
    en_curso: { bg: C.badgeAzul, text: C.azul, label: "En curso" },
    retenido: { bg: "#fff0e6", text: C.naranja, label: "Retenido" },
  };
  const c = colors[pago.estado];
  return (
    <div style={{ background: "#fff", border: `1px solid ${C.borde}`, borderRadius: 14, padding: 14, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
      <div style={{ flex: 1 }}>
        <p style={{ fontSize: 13, fontWeight: 700, color: C.azul, marginBottom: 3 }}>{pago.periodo}</p>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontSize: 11, background: c.bg, color: c.text, padding: "2px 8px", borderRadius: 4, fontWeight: 700 }}>
            {c.label}
          </span>
          <span style={{ fontSize: 11, color: C.gris2 }}>{pago.dias} días</span>
        </div>
      </div>
      <p style={{ fontSize: 16, fontWeight: 700, color: C.azul }}>${pago.monto.toLocaleString("es-MX")}</p>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// PANTALLA 5: MI DESEMPEÑO
// ═══════════════════════════════════════════════════════════════
function Desempeno({ onBack }) {
  const ns = DRIVER.ns_actual;
  let cat, catLabel, ajuste, catColor;
  if (ns >= 99.5) { cat = "excelente"; catLabel = "Excelente"; ajuste = "+5%"; catColor = C.verde; }
  else if (ns >= 98) { cat = "aceptable"; catLabel = "Aceptable"; ajuste = "0%"; catColor = C.gris1; }
  else if (ns >= 95) { cat = "deficiente"; catLabel = "Deficiente"; ajuste = "-2%"; catColor = C.naranja; }
  else { cat = "critico"; catLabel = "Crítico"; ajuste = "-10%"; catColor = C.rojo; }

  const totEntregadas = RUTAS.reduce((s, r) => s + r.entregadas, 0);
  const totParadas = RUTAS.reduce((s, r) => s + r.paradas, 0);
  const totKm = RUTAS.reduce((s, r) => s + r.km, 0);

  // Categorías con su rango y estado activo
  const cats = [
    { key: "excelente", label: "Excelente", range: "99.5% – 100%", ajuste: "+5%", color: C.verde },
    { key: "aceptable", label: "Aceptable", range: "98% – 99.49%", ajuste: "0%", color: C.gris1 },
    { key: "deficiente", label: "Deficiente", range: "95% – 97.99%", ajuste: "-2%", color: C.naranja },
    { key: "critico", label: "Crítico", range: "Menor a 95%", ajuste: "-10%", color: C.rojo },
  ];

  // Arc del velocímetro
  const pct = Math.min(100, Math.max(0, ns));
  const angle = (pct / 100) * 180 - 90;

  return (
    <div>
      <div className="bt-header">
        <button className="bt-back" onClick={onBack}><Icon name="back" size={20} /></button>
        <div className="bt-header-title">Mi Desempeño</div>
      </div>

      <div style={{ padding: 20 }}>
        {/* Velocímetro NS */}
        <div style={{ background: "#fff", borderRadius: 20, padding: 24, border: `1px solid ${C.borde}`, marginBottom: 20, textAlign: "center" }}>
          <p style={{ fontSize: 12, color: C.gris2, fontWeight: 600, letterSpacing: .5, textTransform: "uppercase", marginBottom: 4 }}>
            Nivel de Servicio (NS)
          </p>
          <p style={{ fontSize: 11, color: C.gris3, marginBottom: 18 }}>Últimos 7 días</p>

          <div style={{ position: "relative", width: 220, height: 130, margin: "0 auto 12px" }}>
            <svg viewBox="0 0 220 130" style={{ width: "100%", height: "100%" }}>
              {/* Arco de fondo */}
              <path d="M 20 110 A 90 90 0 0 1 200 110" fill="none" stroke={C.bg3} strokeWidth="18" strokeLinecap="round" />
              {/* Segmentos de colores */}
              <path d="M 20 110 A 90 90 0 0 1 60 40" fill="none" stroke={C.rojo} strokeWidth="4" strokeLinecap="round" opacity=".6" />
              <path d="M 60 40 A 90 90 0 0 1 110 20" fill="none" stroke={C.naranja} strokeWidth="4" strokeLinecap="round" opacity=".6" />
              <path d="M 110 20 A 90 90 0 0 1 160 40" fill="none" stroke={C.gris3} strokeWidth="4" strokeLinecap="round" opacity=".6" />
              <path d="M 160 40 A 90 90 0 0 1 200 110" fill="none" stroke={C.verde} strokeWidth="4" strokeLinecap="round" opacity=".6" />
              {/* Arco de progreso */}
              <path
                d="M 20 110 A 90 90 0 0 1 200 110"
                fill="none" stroke={catColor} strokeWidth="14" strokeLinecap="round"
                strokeDasharray="283" strokeDashoffset={283 - (pct / 100) * 283}
                style={{ transition: ".8s" }}
              />
              {/* Aguja */}
              <g transform={`rotate(${angle} 110 110)`} style={{ transition: ".8s" }}>
                <line x1="110" y1="110" x2="110" y2="30" stroke={C.azul} strokeWidth="3" strokeLinecap="round" />
                <circle cx="110" cy="110" r="8" fill={C.azul} />
                <circle cx="110" cy="110" r="3" fill="#fff" />
              </g>
            </svg>
            <div style={{ position: "absolute", top: "50%", left: 0, right: 0, textAlign: "center", paddingTop: 20 }}>
              <p style={{ fontSize: 42, fontWeight: 800, color: catColor, letterSpacing: -2, lineHeight: 1 }}>{ns}%</p>
            </div>
          </div>

          <div style={{ display: "inline-flex", alignItems: "center", gap: 8, background: catColor + "15", padding: "8px 16px", borderRadius: 10 }}>
            <div style={{ width: 8, height: 8, borderRadius: "50%", background: catColor }} />
            <span style={{ fontSize: 14, fontWeight: 700, color: catColor }}>{catLabel}</span>
            <span style={{ fontSize: 13, color: catColor, fontWeight: 600, opacity: .7 }}>· Ajuste {ajuste}</span>
          </div>
        </div>

        {/* Stats */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 20 }}>
          <DesStat label="Entregas" valor={totEntregadas} sub={`de ${totParadas}`} />
          <DesStat label="Exitosas" valor={`${((totEntregadas/totParadas)*100).toFixed(1)}%`} sub="semana" />
          <DesStat label="Km" valor={Math.round(totKm)} sub="recorridos" />
        </div>

        {/* Tabla de categorías */}
        <div style={{ background: "#fff", borderRadius: 16, padding: 18, border: `1px solid ${C.borde}` }}>
          <h3 style={{ fontSize: 14, fontWeight: 700, color: C.azul, marginBottom: 4 }}>Categorías de NS</h3>
          <p style={{ fontSize: 12, color: C.gris2, marginBottom: 16 }}>
            Según tu NS se aplica un ajuste sobre la tarifa base.
          </p>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {cats.map(c => {
              const isActive = c.key === cat;
              return (
                <div key={c.key} style={{
                  display: "flex", alignItems: "center", gap: 10,
                  padding: "10px 12px", borderRadius: 10,
                  background: isActive ? c.color + "15" : C.bg2,
                  border: isActive ? `1.5px solid ${c.color}` : "1.5px solid transparent",
                }}>
                  <div style={{ width: 4, height: 26, background: c.color, borderRadius: 2 }} />
                  <div style={{ flex: 1 }}>
                    <p style={{ fontSize: 13, fontWeight: 700, color: isActive ? c.color : C.azul }}>
                      {c.label} {isActive && <span style={{ fontSize: 10 }}>← tu nivel</span>}
                    </p>
                    <p style={{ fontSize: 11, color: C.gris2 }}>{c.range}</p>
                  </div>
                  <span style={{ fontSize: 13, fontWeight: 700, color: c.color }}>{c.ajuste}</span>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

function DesStat({ label, valor, sub }) {
  return (
    <div style={{ background: "#fff", borderRadius: 14, padding: 14, border: `1px solid ${C.borde}`, textAlign: "center" }}>
      <p style={{ fontSize: 22, fontWeight: 800, color: C.azul, letterSpacing: -.4, marginBottom: 2 }}>{valor}</p>
      <p style={{ fontSize: 11, color: C.gris1, fontWeight: 600 }}>{label}</p>
      <p style={{ fontSize: 10, color: C.gris2 }}>{sub}</p>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// PANTALLA 6: MIS DOCUMENTOS
// ═══════════════════════════════════════════════════════════════
function Documentos({ onBack }) {
  const [selected, setSelected] = useState(null);
  const aprobados = DOCUMENTOS.filter(d => d.estado === "aprobado").length;
  const total = DOCUMENTOS.length;
  const pct = Math.round((aprobados / total) * 100);

  return (
    <div>
      <div className="bt-header">
        <button className="bt-back" onClick={onBack}><Icon name="back" size={20} /></button>
        <div className="bt-header-title">Mis Documentos</div>
      </div>

      <div style={{ padding: 20 }}>
        {/* Progreso */}
        <div style={{ background: "#fff", borderRadius: 16, padding: 18, border: `1px solid ${C.borde}`, marginBottom: 20 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 10 }}>
            <p style={{ fontSize: 13, fontWeight: 600, color: C.gris1 }}>Documentos aprobados</p>
            <p style={{ fontSize: 20, fontWeight: 800, color: C.azul, letterSpacing: -.5 }}>
              {aprobados}<span style={{ fontSize: 13, color: C.gris2 }}>/{total}</span>
            </p>
          </div>
          <div style={{ height: 8, background: C.bg3, borderRadius: 4, overflow: "hidden" }}>
            <div style={{
              height: "100%", width: `${pct}%`,
              background: `linear-gradient(90deg, ${C.verde} 0%, ${C.naranja} 100%)`,
              borderRadius: 4, transition: ".5s",
            }} />
          </div>
          <p style={{ fontSize: 11, color: C.gris2, marginTop: 8 }}>
            {pct === 100 ? "¡Documentación completa!" : `Falta subir ${total - aprobados} ${total - aprobados === 1 ? "documento" : "documentos"}`}
          </p>
        </div>

        {/* Lista */}
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {DOCUMENTOS.map((d, i) => <DocRow key={i} doc={d} onClick={() => setSelected(d)} />)}
        </div>
      </div>

      {/* Modal detalle doc */}
      {selected && <DocModal doc={selected} onClose={() => setSelected(null)} />}
    </div>
  );
}

function DocRow({ doc, onClick }) {
  const estados = {
    aprobado: { icon: "check", bg: C.verdeClaro, color: C.verde, label: "Aprobado" },
    pendiente: { icon: "bell", bg: "#fff7ed", color: C.naranja, label: "En revisión" },
    rechazado: { icon: "x", bg: C.rojoClaro, color: C.rojo, label: "Rechazado" },
    faltante: { icon: "upload", bg: C.bg3, color: C.gris1, label: "Subir" },
  };
  const e = estados[doc.estado];

  return (
    <div onClick={onClick} style={{ background: "#fff", border: `1px solid ${C.borde}`, borderRadius: 14, padding: 14, display: "flex", alignItems: "center", gap: 12, cursor: "pointer", transition: ".15s" }}>
      <div style={{ width: 42, height: 42, background: e.bg, borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center", color: e.color }}>
        <Icon name={e.icon} size={20} strokeWidth={2.5} />
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <p style={{ fontSize: 13, fontWeight: 700, color: C.azul, marginBottom: 2 }}>{doc.label}</p>
        <p style={{ fontSize: 11, color: e.color, fontWeight: 600 }}>{e.label}</p>
      </div>
      <Icon name="back" size={16} color={C.gris3} strokeWidth={2.5} />
    </div>
  );
}

function DocModal({ doc, onClose }) {
  const estados = {
    aprobado: { color: C.verde, label: "Aprobado", icon: "check" },
    pendiente: { color: C.naranja, label: "En revisión por Bigticket", icon: "bell" },
    rechazado: { color: C.rojo, label: "Rechazado", icon: "x" },
    faltante: { color: C.gris1, label: "No subido", icon: "upload" },
  };
  const e = estados[doc.estado];

  return (
    <div style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,.4)", zIndex: 100, display: "flex", alignItems: "flex-end", animation: "fadeIn .2s" }}>
      <div style={{ width: "100%", background: "#fff", borderRadius: "24px 24px 0 0", padding: 24, animation: "slideUp .3s" }}>
        <div style={{ width: 44, height: 4, background: C.gris4, borderRadius: 2, margin: "0 auto 16px" }} />
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 16 }}>
          <div style={{ width: 48, height: 48, background: e.color + "20", borderRadius: 12, display: "flex", alignItems: "center", justifyContent: "center", color: e.color }}>
            <Icon name={e.icon} size={24} strokeWidth={2.5} />
          </div>
          <div style={{ flex: 1 }}>
            <h3 style={{ fontSize: 16, fontWeight: 700, color: C.azul, marginBottom: 2 }}>{doc.label}</h3>
            <p style={{ fontSize: 13, color: e.color, fontWeight: 600 }}>{e.label}</p>
          </div>
        </div>

        {doc.fecha_sub && (
          <div style={{ background: C.bg2, borderRadius: 10, padding: 12, marginBottom: 12 }}>
            <p style={{ fontSize: 11, color: C.gris2, fontWeight: 600, textTransform: "uppercase", letterSpacing: .3, marginBottom: 3 }}>Subido el</p>
            <p style={{ fontSize: 13, color: C.azul, fontWeight: 600 }}>{doc.fecha_sub}</p>
          </div>
        )}

        {doc.obs && (
          <div style={{ background: C.rojoClaro, borderRadius: 10, padding: 12, marginBottom: 12, borderLeft: `3px solid ${C.rojo}` }}>
            <p style={{ fontSize: 11, color: C.rojo, fontWeight: 700, textTransform: "uppercase", letterSpacing: .3, marginBottom: 3 }}>Observación</p>
            <p style={{ fontSize: 13, color: C.gris1 }}>{doc.obs}</p>
          </div>
        )}

        {(doc.estado === "faltante" || doc.estado === "rechazado") && (
          <button className="bt-btn" style={{ marginBottom: 8 }} onClick={() => { alert("En la app real se abrirá la cámara / selector de archivos"); onClose(); }}>
            <Icon name="upload" size={16} /> Subir documento
          </button>
        )}
        {doc.estado === "aprobado" && (
          <button className="bt-btn bt-btn-ghost" style={{ marginBottom: 8 }}>
            <Icon name="eye" size={16} /> Ver documento
          </button>
        )}
        <button className="bt-btn bt-btn-ghost" onClick={onClose}>Cerrar</button>
      </div>
    </div>
  );
}
// ═══════════════════════════════════════════════════════════════
// PANTALLA 7: DETALLE DE JORNADA
// Se llega tocando una jornada desde Home o Pagos
// ═══════════════════════════════════════════════════════════════
function DetalleJornada({ ruta, onBack, onReclamar }) {
  if (!ruta) {
    return (
      <div style={{ padding: 40, textAlign: "center" }}>
        <p style={{ color: C.gris2, fontSize: 13 }}>No se encontró la jornada.</p>
        <button className="bt-btn bt-btn-ghost" onClick={onBack} style={{ marginTop: 14 }}>Volver</button>
      </div>
    );
  }

  const f = parsearFecha(ruta.fecha);
  const fechaLarga = new Date(ruta.fecha + "T12:00:00").toLocaleDateString("es-MX", {
    weekday: "long", day: "2-digit", month: "long", year: "numeric"
  });
  const fechaCap = fechaLarga.charAt(0).toUpperCase() + fechaLarga.slice(1);

  // Color según categoría
  const catInfo = {
    excelente:  { label: "Excelente",  color: C.verde,   bg: C.verdeClaro },
    aceptable:  { label: "Aceptable",  color: C.azul,    bg: C.badgeAzul },
    deficiente: { label: "Deficiente", color: C.naranja, bg: "#fff0e6" },
    critico:    { label: "Crítico",    color: C.rojo,    bg: C.rojoClaro },
  }[ruta.categoria] || { label: "—", color: C.gris1, bg: C.bg3 };

  // Eficiencia (porcentaje de entregas exitosas)
  const entregaExitosa = ruta.paradas > 0 ? ((ruta.entregadas / ruta.paradas) * 100).toFixed(1) : "0.0";

  return (
    <div>
      <div className="bt-header">
        <button className="bt-back" onClick={onBack}><Icon name="back" size={20} /></button>
        <div>
          <div className="bt-header-title">Jornada {f.dia} {f.mesAbrev}</div>
          <p style={{ fontSize: 11, color: C.gris2, marginTop: 1 }}>Ruta #{ruta.id}</p>
        </div>
      </div>

      <div style={{ padding: 20, paddingBottom: 40 }}>
        {/* Hero con monto y categoría */}
        <div style={{
          background: `linear-gradient(135deg, ${C.azul} 0%, #2a5490 100%)`,
          borderRadius: 20, padding: 22, color: "#fff", marginBottom: 16,
          boxShadow: "0 12px 28px rgba(26,58,107,.22)",
        }}>
          <p style={{ fontSize: 12, opacity: .85, fontWeight: 600, letterSpacing: .3, textTransform: "uppercase", marginBottom: 4 }}>
            Total pagado
          </p>
          <div style={{ display: "flex", alignItems: "baseline", gap: 6, marginBottom: 14 }}>
            <span style={{ fontSize: 38, fontWeight: 800, letterSpacing: -1.5 }}>
              ${ruta.monto.toLocaleString("es-MX")}
            </span>
            <span style={{ fontSize: 14, opacity: .9 }}>MXN</span>
          </div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            <div style={{ background: catInfo.bg, color: catInfo.color, padding: "5px 10px", borderRadius: 8, fontSize: 11, fontWeight: 700 }}>
              {catInfo.label} · NS {ruta.ns}%
            </div>
            <div style={{ background: "rgba(255,255,255,.18)", padding: "5px 10px", borderRadius: 8, fontSize: 11, fontWeight: 600 }}>
              {fechaCap}
            </div>
          </div>
        </div>

        {/* Desglose del pago — lo más importante */}
        <h3 style={{ fontSize: 13, color: C.gris2, fontWeight: 700, letterSpacing: .5, textTransform: "uppercase", marginBottom: 10 }}>
          Desglose del pago
        </h3>
        <div style={{ background: "#fff", borderRadius: 16, border: `1px solid ${C.borde}`, marginBottom: 20, overflow: "hidden" }}>
          <PagoLinea
            label="Tarifa base"
            sub={`${ruta.tipo_vehiculo} · Zona ${ruta.zona} · ${ruta.tramo_km} km`}
            valor={ruta.tarifa_base}
          />
          {ruta.monto_ns !== 0 && (
            <PagoLinea
              label={`Ajuste NS ${ruta.ajuste > 0 ? "+" : ""}${ruta.ajuste}%`}
              sub={ruta.ajuste > 0 ? "Premio por excelencia" : "Multa por servicio deficiente"}
              valor={ruta.monto_ns}
              esAjuste
            />
          )}
          {ruta.monto_auxiliar > 0 && (
            <PagoLinea
              label="Tarifa auxiliar"
              sub={DRIVER.auxiliar_autorizado ? "✓ Auxiliar autorizado" : "Sin autorización"}
              valor={ruta.monto_auxiliar}
            />
          )}
          <div style={{
            padding: "14px 16px", background: C.bg2,
            display: "flex", justifyContent: "space-between", alignItems: "center",
            borderTop: `1px solid ${C.borde}`,
          }}>
            <span style={{ fontSize: 13, fontWeight: 700, color: C.azul, letterSpacing: .3, textTransform: "uppercase" }}>
              Total
            </span>
            <span style={{ fontSize: 18, fontWeight: 800, color: C.azul, letterSpacing: -.3 }}>
              ${ruta.monto.toLocaleString("es-MX")} MXN
            </span>
          </div>
        </div>

        {/* Auxiliar badge informativo */}
        {ruta.con_auxiliar && (
          <div style={{
            background: DRIVER.auxiliar_autorizado ? C.verdeClaro : C.rojoClaro,
            border: `1px solid ${DRIVER.auxiliar_autorizado ? C.verde : C.rojo}`,
            borderRadius: 12, padding: "10px 14px", marginBottom: 20,
            display: "flex", alignItems: "center", gap: 10,
          }}>
            <Icon name={DRIVER.auxiliar_autorizado ? "check" : "x"} size={18}
              color={DRIVER.auxiliar_autorizado ? C.verde : C.rojo} strokeWidth={2.5} />
            <div style={{ flex: 1 }}>
              <p style={{ fontSize: 12, fontWeight: 700, color: DRIVER.auxiliar_autorizado ? C.verde : C.rojo }}>
                {DRIVER.auxiliar_autorizado
                  ? "Operaste con auxiliar autorizado"
                  : "Auxiliar registrado pero NO autorizado"}
              </p>
              <p style={{ fontSize: 11, color: C.gris1, marginTop: 1 }}>
                {DRIVER.auxiliar_autorizado
                  ? "Se pagó la tarifa auxiliar de $300 MXN"
                  : "No se pagó la tarifa auxiliar. Solicita autorización al equipo."}
              </p>
            </div>
          </div>
        )}

        {/* Operación */}
        <h3 style={{ fontSize: 13, color: C.gris2, fontWeight: 700, letterSpacing: .5, textTransform: "uppercase", marginBottom: 10 }}>
          Operación del día
        </h3>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 20 }}>
          <DetailCard label="Paradas asignadas" valor={ruta.paradas} color={C.azul} />
          <DetailCard label="Entregadas" valor={ruta.entregadas} color={C.verde} />
          <DetailCard label="Devueltos" valor={ruta.devueltos} color={ruta.devueltos > 0 ? C.rojo : C.gris1} />
          <DetailCard label="No visitados" valor={ruta.no_visitados} color={ruta.no_visitados > 0 ? C.naranja : C.gris1} />
        </div>

        {/* Eficiencia */}
        <h3 style={{ fontSize: 13, color: C.gris2, fontWeight: 700, letterSpacing: .5, textTransform: "uppercase", marginBottom: 10 }}>
          Eficiencia
        </h3>
        <div style={{ background: "#fff", borderRadius: 16, border: `1px solid ${C.borde}`, marginBottom: 20, overflow: "hidden" }}>
          <InfoLine label="Entrega exitosa" valor={`${entregaExitosa}%`} color={catInfo.color} bold />
          <InfoLine label="Horas en ruta (ORH)" valor={`${ruta.orh.toFixed(2)} h`} />
          <InfoLine label="Paquetes despachados/hora (SPORH)" valor={`${ruta.sporh.toFixed(1)}`} />
          <InfoLine label="Paquetes entregados/hora (DPPH)" valor={`${ruta.dpph.toFixed(1)}`} last />
        </div>

        {/* Vehículo y ruta */}
        <h3 style={{ fontSize: 13, color: C.gris2, fontWeight: 700, letterSpacing: .5, textTransform: "uppercase", marginBottom: 10 }}>
          Vehículo y ruta
        </h3>
        <div style={{ background: "#fff", borderRadius: 16, border: `1px solid ${C.borde}`, marginBottom: 20, overflow: "hidden" }}>
          <InfoLine label="Tipo de vehículo" valor={ruta.tipo_vehiculo} />
          <InfoLine label="Vehículo asignado" valor={ruta.vehiculo} />
          <InfoLine label="Placa" valor={ruta.placa} />
          <InfoLine label="Kilómetros recorridos" valor={`${ruta.km} km`} bold />
          <InfoLine label="Tramo km" valor={`${ruta.tramo_km} km`} last />
        </div>

        {/* Ubicación */}
        <h3 style={{ fontSize: 13, color: C.gris2, fontWeight: 700, letterSpacing: .5, textTransform: "uppercase", marginBottom: 10 }}>
          Ubicación
        </h3>
        <div style={{ background: "#fff", borderRadius: 16, border: `1px solid ${C.borde}`, marginBottom: 20, overflow: "hidden" }}>
          <InfoLine label="Service Center" valor={ruta.service_center} />
          <InfoLine label="Municipio visitado" valor={ruta.municipio} />
          <InfoLine label="Zonificación" valor={`Zona ${ruta.zona}`} bold />
          <InfoLine label="Ciclo" valor={ruta.ciclo} />
          <InfoLine label="Service type" valor={ruta.service_type} last />
        </div>

        {/* Botón de reclamo */}
        <button
          onClick={() => onReclamar(ruta)}
          style={{
            width: "100%", background: "#fff", border: `2px solid ${C.naranja}`,
            color: C.naranja, padding: "14px 20px", borderRadius: 14,
            fontSize: 14, fontWeight: 700, cursor: "pointer",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
            transition: ".15s",
          }}
          onMouseOver={e => { e.currentTarget.style.background = "#fff7ed"; }}
          onMouseOut={e => { e.currentTarget.style.background = "#fff"; }}>
          <span style={{ fontSize: 16 }}>⚠️</span>
          Reportar diferencia con este pago
        </button>
        <p style={{ fontSize: 11, color: C.gris2, textAlign: "center", marginTop: 10, lineHeight: 1.5, padding: "0 12px" }}>
          Si algún dato no coincide con lo que registraste, repórtalo. El equipo revisará y responderá a la brevedad.
        </p>
      </div>
    </div>
  );
}

// Línea de desglose de pago
function PagoLinea({ label, sub, valor, esAjuste, last }) {
  const color = esAjuste && valor < 0 ? C.rojo : esAjuste && valor > 0 ? C.verde : C.azul;
  const signo = esAjuste && valor > 0 ? "+" : "";
  return (
    <div style={{
      padding: "14px 16px",
      display: "flex", justifyContent: "space-between", alignItems: "center",
      borderBottom: last ? "none" : `1px solid ${C.borde}`,
    }}>
      <div style={{ flex: 1, minWidth: 0 }}>
        <p style={{ fontSize: 13, fontWeight: 600, color: C.azul, marginBottom: 2 }}>{label}</p>
        {sub && <p style={{ fontSize: 11, color: C.gris2 }}>{sub}</p>}
      </div>
      <p style={{ fontSize: 15, fontWeight: 700, color, marginLeft: 12, whiteSpace: "nowrap" }}>
        {signo}${Math.abs(valor).toLocaleString("es-MX")}
      </p>
    </div>
  );
}

// Card pequeño para operación
function DetailCard({ label, valor, color }) {
  return (
    <div style={{ background: "#fff", borderRadius: 12, padding: 14, border: `1px solid ${C.borde}` }}>
      <p style={{ fontSize: 11, color: C.gris2, fontWeight: 600, marginBottom: 4, letterSpacing: .2 }}>{label}</p>
      <p style={{ fontSize: 22, fontWeight: 800, color, letterSpacing: -.5 }}>{valor}</p>
    </div>
  );
}

// Línea de info genérica
function InfoLine({ label, valor, color, bold, last }) {
  return (
    <div style={{
      padding: "12px 16px",
      display: "flex", justifyContent: "space-between", alignItems: "center", gap: 10,
      borderBottom: last ? "none" : `1px solid ${C.borde}`,
    }}>
      <p style={{ fontSize: 12, color: C.gris1, flex: 1 }}>{label}</p>
      <p style={{
        fontSize: 13, fontWeight: bold ? 700 : 600,
        color: color || C.azul, textAlign: "right", whiteSpace: "nowrap",
      }}>{valor}</p>
    </div>
  );
}

